INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES ("", 1007404, 1007404054, 0, "", 21, "", 0, "", "vo_mhp_1007404", "vo_mhp_1007");
INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES (0.5, 1007404, 1007404055, 1, 0, 11, 0, 5, 0, 117531, "そうね、逞しい人たちだものね……\nはあ、懐かしい。あの人たちには昔、\nよく研究のことで因縁をつけられたわ。");
INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES ("", 1007404, 1007404056, "", "", 91, "", "", "", 0, 0);
