INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES ("", 1007406, 1007406036, 0, "", 21, "", 0, "", "vo_mhp_1007406", "vo_mhp_1204");
INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES (0.5, 1007406, 1007406037, 1, 0, 11, 0, 5, 0, 117531, "さて、ユニちゃん──ああ失礼、\n今は学位持ちだったわね。\nユニ博士とお呼びするべきかしら？");
INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES ("", 1007406, 1007406038, "", "", 91, "", "", "", 0, "");
