INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES ("", 1007406, 1007406041, 0, "", 21, "", 0, "", "vo_mhp_1007406", "vo_mhp_1205");
INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES (0.5, 1007406, 1007406042, 1, 0, 11, 0, 6, 0, 111011, "いや、結構。\n学院の都合で押しつけられた\n名誉学位などニックネームにも同義だ。");
INSERT INTO `v1_ad3cb03d6362a5c69075bcb64587154de5de108168f9af079f15b7de069df938` VALUES ("", 1007406, 1007406043, "", "", 91, "", "", "", 0, "");
